DROP TABLE IF EXISTS bridge.key_crosswalk;
DROP TABLE IF EXISTS dim.security;
DROP TABLE IF EXISTS dim.asset;
DROP TABLE IF EXISTS dim.entity;
DROP TABLE IF EXISTS dim.portfolio;
DROP TABLE IF EXISTS dim.portfolio_group;
DROP TABLE IF EXISTS dim.investor;
DROP TABLE IF EXISTS dim.department_group;
DROP TABLE IF EXISTS dim.department;
DROP TABLE IF EXISTS bridge.key_domain;
DROP TABLE IF EXISTS bridge.source_registry;
DROP TABLE IF EXISTS bridge.bridge_tag;
DROP TABLE IF EXISTS bridge.tag;
DROP TABLE IF EXISTS bridge.bridge_definition;
DROP TABLE IF EXISTS bridge.bridge_category;
DROP TABLE IF EXISTS bridge.execution_detail_log;
DROP TABLE IF EXISTS bridge.execution_log;
*/

-- ============================================================================
-- SECTION 1: SOURCE & KEY METADATA
-- ============================================================================

-- 1.1 SOURCE REGISTRY ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS bridge.source_registry (
    source_id           BIGINT       GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    source_code         STRING       NOT NULL,
    source_name         STRING       NOT NULL,
    source_type         STRING       NOT NULL,    -- INTERNAL, EXTERNAL
    description         STRING,
    connection_type     STRING,                   -- API, SFTP, DATABASE, MANUAL
    refresh_frequency   STRING,                   -- REALTIME, DAILY, WEEKLY, MONTHLY
    is_active           BOOLEAN      NOT NULL DEFAULT TRUE,
    created_at          TIMESTAMP    NOT NULL DEFAULT current_timestamp(),
    created_by          STRING       NOT NULL DEFAULT current_user(),
    modified_at         TIMESTAMP,
    modified_by         STRING
    -- CONSTRAINT uq_source_registry_code UNIQUE (source_code)  -- disabled on Free Edition
)
TBLPROPERTIES (
    -- Enables column DEFAULT values; required because every column with a DEFAULT
    -- clause needs this Delta table feature explicitly opted in.
    'delta.feature.allowColumnDefaults' = 'supported',
    -- Assigns each row a stable, monotonic _metadata.row_id and tracks commit
    -- versions per row. Required for materialized view incremental refresh
    -- (enzyme uses row IDs to compute deltas without full recomputation).
    'delta.enableRowTracking' = 'true',
    -- Exposes the change-data-feed via table_changes(). Lets downstream
    -- streaming tables and incremental consumers read inserts/updates/deletes
    -- as a stream of change events rather than re-scanning the whole table.
    'delta.enableChangeDataFeed' = 'true'
);

-- 1.2 KEY DOMAIN --------------------------------------------------------------
CREATE TABLE IF NOT EXISTS bridge.key_domain (
    domain_id               BIGINT      GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    domain_code             STRING      NOT NULL,
    domain_name             STRING      NOT NULL,
    description             STRING,
    dimension_schema        STRING,
    dimension_table         STRING,
    dimension_key_column    STRING,
    is_active               BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at              TIMESTAMP   NOT NULL DEFAULT current_timestamp(),
    created_by              STRING      NOT NULL DEFAULT current_user(),
    modified_at             TIMESTAMP,
    modified_by             STRING
    -- CONSTRAINT uq_key_domain_code UNIQUE (domain_code)  -- disabled on Free Edition
)
TBLPROPERTIES (
    -- Enables column DEFAULT values; required because every column with a DEFAULT
    -- clause needs this Delta table feature explicitly opted in.
    'delta.feature.allowColumnDefaults' = 'supported',
    -- Assigns each row a stable, monotonic _metadata.row_id and tracks commit
    -- versions per row. Required for materialized view incremental refresh
    -- (enzyme uses row IDs to compute deltas without full recomputation).
    'delta.enableRowTracking' = 'true',
    -- Exposes the change-data-feed via table_changes(). Lets downstream
    -- streaming tables and incremental consumers read inserts/updates/deletes
    -- as a stream of change events rather than re-scanning the whole table.
    'delta.enableChangeDataFeed' = 'true'
);

