-- ============================================================================
-- SECTION 4: KEY CROSSWALK BRIDGE
-- ============================================================================
CREATE TABLE IF NOT EXISTS bridge.key_crosswalk (
    crosswalk_sk            BIGINT      GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    domain_id               BIGINT      NOT NULL,
    source_system_id        BIGINT      NOT NULL,
    source_key              STRING      NOT NULL,
    source_key_secondary    STRING,
    target_system_id        BIGINT      NOT NULL,
    target_key              STRING      NOT NULL,
    target_key_secondary    STRING,
    relationship_type       STRING      NOT NULL DEFAULT 'ONE_TO_ONE',
    split_sequence          INT,
    split_description       STRING,
    -- SCD2
    is_current              BOOLEAN     NOT NULL DEFAULT TRUE,
    effective_start_date    DATE        NOT NULL DEFAULT current_date(),
    effective_end_date      DATE,
    preceding_record_sk     BIGINT,
    succeeding_record_sk    BIGINT,
    -- Audit
    created_at              TIMESTAMP   NOT NULL DEFAULT current_timestamp(),
    created_by              STRING      NOT NULL DEFAULT current_user(),
    modified_at             TIMESTAMP,
    modified_by             STRING,
    CONSTRAINT fk_xwalk_domain FOREIGN KEY (domain_id)
        REFERENCES bridge.key_domain(domain_id) NOT ENFORCED,
    CONSTRAINT fk_xwalk_source FOREIGN KEY (source_system_id)
        REFERENCES bridge.source_registry(source_id) NOT ENFORCED,
    CONSTRAINT fk_xwalk_target FOREIGN KEY (target_system_id)
        REFERENCES bridge.source_registry(source_id) NOT ENFORCED
)
CLUSTER BY (domain_id, source_system_id, source_key)
TBLPROPERTIES (
    -- Enables column DEFAULT values; required because every column with a DEFAULT
    -- clause needs this Delta table feature explicitly opted in.
    'delta.feature.allowColumnDefaults' = 'supported',
    -- Assigns each row a stable, monotonic _metadata.row_id and tracks commit
    -- versions per row. Required for materialized view incremental refresh
    -- (enzyme uses row IDs to compute deltas without full recomputation).
