CREATE TABLE IF NOT EXISTS bridge.execution_log (
    execution_id        BIGINT      GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    -- execution_guid: callers must supply uuid() on INSERT.
    -- Delta rejects non-deterministic expressions (uuid(), rand()) as DEFAULTs.
    execution_guid      STRING      NOT NULL,
    category_id         BIGINT,
    tag_filter          STRING,
    execution_mode      STRING      NOT NULL DEFAULT 'FULL',
    status              STRING      NOT NULL DEFAULT 'RUNNING',
    started_at          TIMESTAMP   NOT NULL DEFAULT current_timestamp(),
    completed_at        TIMESTAMP,
    duration_seconds    DECIMAL(12,3),
    executed_by         STRING      NOT NULL DEFAULT current_user(),
